import React from 'react';
import './Awards.css';
import { AWARDS } from '../../Util/data';

const Awards = () => {
    const getTypeColor = (type) => {
        const colors = {
            academic: "#6366f1",
            industry: "#10b981", 
            scholarship: "#f59e0b",
            honor: "#ef4444",
            competition: "#8b5cf6"
        };
        return colors[type] || "#6b7280";
    };

    const getTypeLabel = (type) => {
        const labels = {
            academic: "Academic",
            industry: "Industry",
            scholarship: "Scholarship",
            honor: "Honor",
            competition: "Competition"
        };
        return labels[type] || "Other";
    };

    return (
        <section id="awards" className="awards-section">
            <div className="awards-header">
                <h1>
                    <span role="img" aria-label="awards">🏆</span>
                    {' '}Awards and Honors
                </h1>
            </div>
            
            <div className="awards-container">
                {AWARDS.map((award, index) => (
                    <div key={index} className="award-item" data-type={award.type}>
                        <div className="award-icon">{award.icon}</div>
                        <div className="award-year">{award.year}</div>
                        <div className="award-content">
                            <div className="award-title">{award.title}</div>
                            <div className="award-highlight">• {award.highlight}</div>
                        </div>
                        <div 
                            className="award-type-badge" 
                            style={{ backgroundColor: getTypeColor(award.type) }}
                        >
                            {getTypeLabel(award.type)}
                        </div>
                    </div>
                ))}
            </div>
        </section>
    );
};

export default Awards;
